1	import { useCallback, useEffect, useRef, useState } from 'react';
2	
3	import type { Snapshot } from '@bim-ai/core';
4	
5	import {
6	  bootstrap,
7	  coerceDelta,
8	  fetchActivity,
9	  fetchBuildingPresets,
10	  fetchComments,
11	} from '../lib/api';
12	import { log } from '../logger';
13	import { useBimStore } from '../state/store';
14	import { mapComments } from './workspaceUtils';
15	
16	const DISABLE_WS =
17	  typeof import.meta.env.VITE_E2E_DISABLE_WS === 'string' &&
18	  ['1', 'true', 'yes'].includes(import.meta.env.VITE_E2E_DISABLE_WS.trim().toLowerCase());
19	
20	const MAX_RECONNECT_ATTEMPTS = 10;
21	
22	export function useWorkspaceSnapshot(): {
23	  insertSeedHouse: () => Promise<void>;
24	  seedLoading: boolean;
25	  seedError: string | null;
26	  setSeedError: (err: string | null) => void;
27	  wsOn: boolean;
28	  codePresetIds: string[];
29	} {
30	  const hydrateFromSnapshot = useBimStore((s) => s.hydrateFromSnapshot);
31	  const setActivity = useBimStore((s) => s.setActivity);
32	  const applyDelta = useBimStore((s) => s.applyDelta);
33	  const setPresencePeers = useBimStore((s) => s.setPresencePeers);
34	  const mergeComment = useBimStore((s) => s.mergeComment);
35	  const setComments = useBimStore((s) => s.setComments);
36	  const elementsById = useBimStore((s) => s.elementsById);
37	  const modelId = useBimStore((s) => s.modelId);
38	
39	  const [seedLoading, setSeedLoading] = useState(false);
40	  const [seedError, setSeedError] = useState<string | null>(null);
41	  const [wsOn, setWsOn] = useState(false);
42	  const [codePresetIds, setCodePresetIds] = useState<string[]>([
43	    'residential',
44	    'commercial',
45	    'office',
46	  ]);
47	  const wsRef = useRef<WebSocket | null>(null);
48	  const lastSeqRef = useRef<number | null>(null);
49	  const reconnectAttemptsRef = useRef(0);
50	  const reconnectTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
51	  const mountedRef = useRef(true);
52	
53	  const connectWs = useCallback(
54	    (mid: string, lastSeq: number | null): WebSocket => {
55	      const p = window.location.protocol === 'https:' ? 'wss' : 'ws';
56	      const resumeParam = lastSeq !== null ? `?resumeFrom=${lastSeq}` : '';
57	      const ws = new WebSocket(
58	        `${p}://${window.location.host}/ws/${encodeURIComponent(mid)}${resumeParam}`,
59	      );
60	
61	      ws.onopen = () => {
62	        reconnectAttemptsRef.current = 0;
63	        setWsOn(true);
64	      };
65	
66	      ws.onclose = () => {
67	        setWsOn(false);
68	        if (DISABLE_WS || !mountedRef.current) return;
69	
70	        const attempt = reconnectAttemptsRef.current + 1;
71	        reconnectAttemptsRef.current = attempt;
72	
73	        if (attempt > MAX_RECONNECT_ATTEMPTS) {
74	          console.warn('[bim-ai/ws] offline: max reconnect attempts reached');
75	          return;
76	        }
77	
78	        const baseDelay = Math.min(250 * 2 ** (attempt - 1), 8000);
79	        const jitter = baseDelay * 0.2 * (Math.random() * 2 - 1);
80	        const delay = Math.max(0, Math.round(baseDelay + jitter));
81	
82	        const doReconnect = () => {
83	          if (!mountedRef.current) return;
84	          wsRef.current?.close();
85	          wsRef.current = connectWs(mid, lastSeqRef.current);
86	        };
87	
88	        if (document.visibilityState === 'hidden') {
89	          const onVisible = () => {
90	            if (document.visibilityState !== 'hidden') {
91	              document.removeEventListener('visibilitychange', onVisible);
92	              doReconnect();
93	            }
94	          };
95	          document.addEventListener('visibilitychange', onVisible);
96	        } else {
97	          reconnectTimerRef.current = setTimeout(doReconnect, delay);
98	        }
99	      };
100	
101	      ws.onmessage = (evt) => {
102	        const payload = JSON.parse(String(evt.data)) as Record<string, unknown>;
103	        const t = payload.type;
104	
105	        const seq = payload.seq;
106	        if (typeof seq === 'number') {
107	          lastSeqRef.current = seq;
108	        }
109	
110	        if (t === 'snapshot') {
111	          const s = payload as unknown as Snapshot;
112	          if (s.modelId) hydrateFromSnapshot(s);
113	        } else if (t === 'delta') {
114	          const dd = coerceDelta(payload);
115	          if (dd) applyDelta(dd);
116	        } else if (t === 'presence_state') {
117	          const pl = payload.payload as Record<string, unknown> | undefined;
118	          const px = ((pl?.peers as Record<string, unknown>) ?? {}) as Parameters<
119	            typeof setPresencePeers
120	          >[0];
121	          setPresencePeers(px);
122	        } else if (t === 'comment_event') {
123	          const w = payload.payload as Record<string, unknown> | undefined;
124	          if (!w) return;
125	          mergeComment(mapComments([w])[0]!);
126	        } else if (t === 'RESYNC') {
127	          void (async () => {
128	            try {
129	              const snapRes = await fetch(
130	                `/api/models/${encodeURIComponent(mid)}/snapshot?expandLinks=true`,
131	              );
132	              if (!snapRes.ok) throw new Error(`snapshot ${snapRes.status}`);
133	              const snap = (await snapRes.json()) as Snapshot;
134	              hydrateFromSnapshot(snap);
135	              lastSeqRef.current = null;
136	            } catch (err) {
137	              log.error('ws', 'RESYNC snapshot fetch failed', err);
138	            }
139	          })();
140	        } else if (t === 'replay_done') {
141	          log.info('ws', 'replay_done received');
142	        }
143	      };
144	
145	      return ws;
146	    },
147	    [hydrateFromSnapshot, applyDelta, setPresencePeers, mergeComment],
148	  );
149	
150	  const insertSeedHouse = useCallback(async (): Promise<void> => {
151	    setSeedLoading(true);
152	    setSeedError(null);
153	    try {
154	      const bx = await bootstrap();
155	      const pj = bx.projects as Record<string, unknown>[] | undefined;
156	      const m0 = pj?.[0]?.models as Array<{ id?: unknown }> | undefined;
157	      const mid = m0?.[0]?.id;
158	      if (typeof mid !== 'string') throw new Error('No models — run make seed');
159	      const snapRes = await fetch(
160	        `/api/models/${encodeURIComponent(mid)}/snapshot?expandLinks=true`,
161	      );
162	      if (!snapRes.ok) throw new Error(`snapshot ${snapRes.status}`);
163	      const snap = (await snapRes.json()) as Snapshot;
164	      hydrateFromSnapshot(snap);
165	      // activityEvents/comments are populated by the modelId effect below — they
166	      // are model-scoped server state and must invalidate together with modelId.
167	      if (!DISABLE_WS) {
168	        wsRef.current = connectWs(mid, null);
169	      }
170	    } catch (err) {
171	      setSeedError(err instanceof Error ? err.message : 'Failed to load seed');
172	    } finally {
173	      setSeedLoading(false);
174	    }
175	  }, [hydrateFromSnapshot, connectWs]);
176	
177	  // modelId is the cache key for server-fetched, model-scoped state. Whenever
178	  // it changes, prior activity/comments must be cleared (so the previous
179	  // model's history doesn't bleed into the new one) and refetched. Empty/unset
180	  // modelIds clear without fetching.
181	  useEffect(() => {
182	    setActivity([]);
183	    setComments([]);
184	    if (!modelId || modelId === 'empty') return;
185	    let cancelled = false;
186	    void fetchActivity(modelId)
187	      .then((a) => {
188	        if (cancelled) return;
189	        const evs = ((a.events ?? []) as Record<string, unknown>[]).map((ev) => ({
190	          id: Number(ev.id),
191	          userId: String(ev.userId ?? ev.user_id ?? ''),
192	          revisionAfter: Number(ev.revisionAfter ?? ev.revision_after ?? 0),
193	          createdAt: String(ev.createdAt ?? ev.created_at ?? ''),
194	          commandTypes: Array.isArray(ev.commandTypes) ? ev.commandTypes.map(String) : [],
195	        }));
196	        setActivity(evs);
197	      })
198	      .catch((err) => log.error('modelId', 'fetchActivity failed', err));
199	    void fetchComments(modelId)
200	      .then((c) => {
201	        if (cancelled) return;
202	        setComments(mapComments((c.comments ?? []) as Record<string, unknown>[]));
203	      })
204	      .catch((err) => log.error('modelId', 'fetchComments failed', err));
205	    return () => {
206	      cancelled = true;
207	    };
208	  }, [modelId, setActivity, setComments]);
209	
210	  useEffect(() => {
211	    void fetchBuildingPresets()
212	      .then((ids) => {
213	        if (ids.length) setCodePresetIds(ids);
214	      })
215	      .catch((err) => log.error('bootstrap', 'fetchBuildingPresets failed', err));
216	  }, []);
217	
218	  useEffect(() => {
219	    const isEmpty = Object.keys(elementsById).length === 0;
220	    if (!isEmpty) return;
221	    void insertSeedHouse();
222	    return () => {
223	      mountedRef.current = false;
224	      reconnectAttemptsRef.current = Infinity;
225	      if (reconnectTimerRef.current !== null) clearTimeout(reconnectTimerRef.current);
226	      wsRef.current?.close();
227	      wsRef.current = null;
228	    };
229	    // Run-once bootstrap: re-running is the user's job via the empty-state CTA.
230	    // eslint-disable-next-line react-hooks/exhaustive-deps
231	  }, []);
232	
233	  // Presence heartbeat — sends viewer/selection state to collaborators every ~2.3s
234	  useEffect(() => {
235	    const id = window.setInterval(() => {
236	      const ws = wsRef.current;
237	      if (!ws || ws.readyState !== WebSocket.OPEN) return;
238	      const st = useBimStore.getState();
239	      ws.send(
