      pass.edgeGlow = 0.0;
      pass.edgeThickness = 1.5;
      pass.visibleEdgeColor.set(color);
      pass.hiddenEdgeColor.set(color);
      composer.passes.splice(outputPassIdx, 0, pass);
      remotePasses.set(color, pass);
    }
    pass.selectedObjects = objs;
  }
}, [remoteSelections]);

